CREATE TABLE menus (menu_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), restaurant_id UUID UNIQUE NOT NULL REFERENCES restaurants(restaurant_id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE menu_categories (category_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), menu_id UUID NOT NULL REFERENCES menus(menu_id) ON DELETE CASCADE, name VARCHAR(80) NOT NULL, sort_order INT NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE menu_items (item_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), restaurant_id UUID NOT NULL REFERENCES restaurants(restaurant_id) ON DELETE CASCADE, category_id UUID REFERENCES menu_categories(category_id) ON DELETE SET NULL, name VARCHAR(200) NOT NULL, price DECIMAL(10,2) NOT NULL CHECK(price>0), is_available BOOLEAN NOT NULL DEFAULT TRUE, is_deleted BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
